import"./ticker-BxUDbM2L.js";import{i as a}from"./country-page-CK6BdUjw.js";/* empty css                  */import"./utils-Owvk3OYq.js";import"./breadcrumbs-CxxVGuAV.js";a({navDepth:2,breadcrumbParent:{label:"Saudi Arabia Gold",url:"../../saudi-arabia.html"},countryCode:"SA",currency:"SAR",flag:"🇸🇦",nameEn:"Riyadh, Saudi Arabia",nameAr:"الرياض، المملكة العربية السعودية",fixedPeg:!1,decimals:2,timezone:"Asia/Riyadh",relatedCountries:[{file:"../../saudi-arabia.html",nameEn:"Saudi Arabia",nameAr:"السعودية",flag:"🇸🇦"},{file:"../../uae.html",nameEn:"UAE",nameAr:"الإمارات",flag:"🇦🇪"},{file:"../../kuwait.html",nameEn:"Kuwait",nameAr:"الكويت",flag:"🇰🇼"},{file:"../../qatar.html",nameEn:"Qatar",nameAr:"قطر",flag:"🇶🇦"},{file:"../../bahrain.html",nameEn:"Bahrain",nameAr:"البحرين",flag:"🇧🇭"}],faqEn:[{q:"What is the gold price in Riyadh today?",a:"The live gold price in Riyadh is shown above in Saudi Riyals (SAR) per gram. It is updated every 90 seconds. The SAR is pegged to the USD at 3.75, so prices track global spot directly."},{q:"What karat is most popular for gold in Saudi Arabia?",a:"21 karat and 22 karat are the most popular karats for jewellery in Saudi Arabia. 18 karat is common for modern and European-style designs. 24 karat is used for bullion bars and investment coins."},{q:"Is there VAT on gold in Saudi Arabia?",a:"Saudi Arabia's 15% VAT applies to most retail transactions. However, investment-grade gold (bullion bars and coins) is generally exempt or zero-rated. Jewellery pieces are typically subject to VAT. Verify the exact treatment with the retailer at point of purchase, as rules can vary by classification."},{q:"How is gold pricing regulated in Saudi Arabia?",a:"Saudi gold retailers are required to display the daily gold rate per gram, published based on global spot prices. The Saudi Standards Authority (SASO) mandates hallmarking of gold jewellery sold in the Kingdom, with karat purity marks required on all pieces."}],faqAr:[{q:"ما هو سعر الذهب في الرياض اليوم؟",a:"يُعرض سعر الذهب الحالي في الرياض بالريال السعودي (SAR) للغرام أعلاه، ويُحدَّث كل 90 ثانية. الريال مرتبط بالدولار بسعر 3.75 ثابت."},{q:"ما هو العيار الأكثر شيوعاً في المملكة العربية السعودية؟",a:"عيارا 21 و22 هما الأكثر انتشاراً للمجوهرات في السعودية. عيار 18 شائع في التصاميم الحديثة، وعيار 24 للسبائك والعملات الاستثمارية."},{q:"هل هناك ضريبة على الذهب في السعودية؟",a:"ضريبة القيمة المضافة 15% تُطبَّق على معظم المعاملات. أما الذهب الاستثماري (السبائك والعملات) فهو عموماً معفى. المجوهرات تخضع عادةً للضريبة. تحقق من التجزئة عند الشراء."}]});
